// 产 DXF/SVG 字符串,零全局足迹;default 命名空间导入
import makerjs from 'https://cdn.jsdelivr.net/npm/makerjs@0.19.2/+esm';
const ctors = makerjs.models;
const model = { units: data.units ?? 'mm', models: {} };
(data.models ?? []).forEach((m, i) => {
  model.models['m' + i] = new ctors[m.type](...(m.args ?? []));
});
const out = data.export === 'dxf'
  ? makerjs.exporter.toDXF(model)
  : makerjs.exporter.toSVG(model, { units: model.units });
// DXF: new Blob([out],{type:'application/dxf'}) 下载
// SVG: const d=document.createElement('div'); d.innerHTML=out; (widget) shadowRoot.appendChild(d) / (artifact) targetEl.appendChild(d)
